// Guard: skip if subagent context
if (_batchLoadSubagent > 0 || isSubagentContext()) return;

// System prompt injection: forces delegate-only mode
pi.on("before_agent_start", async (event, ctx) => {
  pi.setActiveTools(["delegate"]);
  return { systemPrompt: cleanedPrompt + delegationInstructions };
});

// Safety net: block non-delegate calls
pi.on("tool_call", async (event, ctx) => {
  if (event.toolName !== "delegate") {
    return { block: true, reason: `Orchestrator mode: use delegate() instead` };
  }
});
```

